def create_schedule(tasks: List[str], time_slots: List[str]):
    schedule = []
    for time_slot in time_slots:
        schedule_time = []
        for task in tasks:
            schedule_time.append(None)
        schedule.append(schedule_time)

    for task, time_slot in zip(tasks, time_slots):
        schedule[time_slots.index(time_slot)][tasks.index(task)] = task

    return schedule

# Example
tasks = ["Breakfast", "Shower", "Get Dressed", "Leave for Work", "Work"]
time_slots = ["6:00 AM", "6:30 AM", "7:00 AM", "7:30 AM", "8:00 AM"]

print(create_schedule(tasks, time_slots))

